SELECT 'leads' as stage, COUNT(*) as count FROM crm_lead WHERE deleted = 0 AND created_time BETWEEN #{startDate} AND #{endDate}
UNION ALL
SELECT 'customers' as stage, COUNT(*) as count FROM crm_customer WHERE deleted = 0 AND created_time BETWEEN #{startDate} AND #{endDate}
UNION ALL
SELECT 'inquiries' as stage, COUNT(*) as count FROM crm_inquiry WHERE deleted = 0 AND created_time BETWEEN #{startDate} AND #{endDate}
UNION ALL
SELECT 'quotations' as stage, COUNT(*) as count FROM crm_quotation WHERE deleted = 0 AND created_time BETWEEN #{startDate} AND #{endDate}
UNION ALL
SELECT 'orders' as stage, COUNT(*) as count FROM crm_order WHERE deleted = 0 AND order_date BETWEEN #{startDate} AND #{endDate}
